def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity == 0:
            priorities[i] = np.inf
            continue
        ratio = item / capacity
        if ratio > 2:
            priorities[i] = ratio ** 4 + np.sqrt(ratio)
        elif 1 < ratio <= 2:
            priorities[i] = ratio ** 3 - np.log(ratio)
        elif ratio == 1:
            priorities[i] = 0
        else:
            log_ratio = np.log(ratio)
            if log_ratio < -2:
                priorities[i] = (-log_ratio) * 3 + ratio * 2
            elif log_ratio < -1:
                priorities[i] = (-log_ratio) * 2 + ratio
            else:
                priorities[i] = -log_ratio
        if capacity < item:
            priorities[i] *= 2
        elif capacity < item * 1.2:
            priorities[i] *= 1.7
        elif capacity < item * 1.5:
            priorities[i] *= 1.3
        else:
            priorities[i] *= 0.5
        if i % 2 == 0:
            priorities[i] += np.sin(capacity) * 0.1
        else:
            priorities[i] -= np.cos(capacity) * 0.1
    finite_priorities = priorities[np.isfinite(priorities)]
    if finite_priorities.size > 0:
        min_priority = np.min(finite_priorities)
        max_priority = np.max(finite_priorities)
        for i in range(len(priorities)):
            if not np.isfinite(priorities[i]):
                priorities[i] = max_priority * 10
            elif priorities[i] < min_priority:
                priorities[i] = min_priority
            elif priorities[i] > max_priority:
                priorities[i] = max_priority
    else:
        priorities.fill(np.inf)
    for i in range(len(priorities)):
        if priorities[i] < 0:
            priorities[i] = 0
    return priorities
